1370 |         async function decryptCtx(buffer) {
1371 |             const keyBytes = new TextEncoder().encode("C0rtexS3cr3tK3y!");
1372 |             const iv = buffer.slice(0, 12);
1373 |             const ciphertext = buffer.slice(12);
1374 |             
1375 |             const cryptoKey = await crypto.subtle.importKey("raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]);
1376 |             const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv }, cryptoKey, ciphertext);
1377 |             
1378 |             const decompressedBuffer = await decompressGzip(decrypted);
1379 |             return JSON.parse(new TextDecoder().decode(decompressedBuffer));
1380 |         }
