1382 |         async function decompressGzip(buffer) {
1383 |             const ds = new DecompressionStream("gzip");
1384 |             const writer = ds.writable.getWriter();
1385 |             writer.write(buffer);
1386 |             writer.close();
1387 |             const response = new Response(ds.readable);
1388 |             return await response.arrayBuffer();
1389 |         }
